import { useEffect, useState } from 'react';

const Count = ({ day }) => {
  // Estado para el contador
  const [timeLeft, setTimeLeft] = useState(calculateTimeLeft(day));

  // Calcula la diferencia entre la fecha futura y la fecha actual
  function calculateTimeLeft(day) {
    const difference = new Date(day) - new Date();

    if (difference <= 0) {
      return {
        days: 0,
        hours: 0,
        minutes: 0,
        seconds: 0,
      };
    }

    const days = Math.floor(difference / (1000 * 60 * 60 * 24));
    const hours = Math.floor(
      (difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)
    );
    const minutes = Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60));
    const seconds = Math.floor((difference % (1000 * 60)) / 1000);

    return { days, hours, minutes, seconds };
  }

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft(day));
    }, 1000);

    return () => clearInterval(timer);
  }, [day]);

  return (
    <div>
      <h1>Cuenta atrás:</h1>
      <p>
        {timeLeft.days} días, {timeLeft.hours} horas, {timeLeft.minutes}{' '}
        minutos, {timeLeft.seconds} segundos
      </p>
    </div>
  );
};

export default Count;
